const fs = require('fs');
const body = $input.first().json.body;
const now = new Date().toLocaleString('en-US', {
  timeZone: 'America/Los_Angeles',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

const fields = [
  ['contact_name', 'Contact'],
  ['contact_method', 'Preferred Contact Method'],
  ['contact_detail', 'Contact Info'],
  ['pricing', 'Current Pricing'],
  ['service_area', 'Service Area'],
  ['partner_clinics', 'Partner Clinics'],
  ['monthly_volume', 'Monthly Volume'],
  ['hours', 'Hours'],
  ['tier', 'Tier Interest'],
  ['photos', 'Photos Available'],
  ['photo_link', 'Photo Upload Link'],
  ['demo_feedback', 'Demo Site Feedback'],
  ['corrections', 'Corrections'],
  ['anything_else', 'Other Notes']
];

const summary = {};
let md = '\n---\n\n## ' + now + '\n\n';
let notify = '';

for (const [key, label] of fields) {
  const val = body && body[key];
  if (val && String(val).trim()) {
    summary[label] = String(val).trim();
    md += '**' + label + ':** ' + String(val).trim() + '\n\n';
    notify += label + ': ' + String(val).trim() + '\n';
  }
}

const filePath = '/peach-logs/petmex-intake.md';
if (!fs.existsSync(filePath)) {
  fs.writeFileSync(filePath, '# PetMex Intake Submissions\n\n');
}
fs.appendFileSync(filePath, md);

const contactName = (body && body.contact_name) || 'Unknown';

return [{
  json: {
    timestamp: now,
    submission: summary,
    raw: body,
    notifyTitle: 'PetMex Intake: ' + contactName,
    notifyBody: notify
  }
}];
